#!/usr/bin/env node
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "esbuild";

const repoRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const runtimeDistDir = path.join(repoRoot, "runtime-dist");
const generatedHeader = [
  "#!/usr/bin/env node",
  "// Generated by scripts/generate-runtime-dist.mjs. Do not edit directly."
].join("\n");

const entryPoints = {
  "materialize-global-xgc": path.join(repoRoot, "scripts", "materialize-global-xgc.ts"),
  "validate-global-xgc": path.join(repoRoot, "scripts", "validate-global-xgc.ts"),
  "xgc-update": path.join(repoRoot, "scripts", "xgc-update.mjs"),
  "xgc-uninstall": path.join(repoRoot, "scripts", "uninstall-global-xgc.mjs")
};

function listFilesRecursive(root) {
  const files = [];

  const walk = (current) => {
    if (!fs.existsSync(current)) {
      return;
    }
    for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
      const fullPath = path.join(current, entry.name);
      if (entry.isDirectory()) {
        walk(fullPath);
      } else {
        files.push(path.relative(root, fullPath));
      }
    }
  };

  walk(root);
  return files.sort();
}

async function buildRuntimeDist(outputDir) {
  fs.rmSync(outputDir, { recursive: true, force: true });
  fs.mkdirSync(outputDir, { recursive: true });

  await build({
    entryPoints,
    outdir: outputDir,
    bundle: true,
    format: "esm",
    platform: "node",
    target: "node20",
    outExtension: { ".js": ".mjs" }
  });

  for (const entryName of Object.keys(entryPoints)) {
    const outputFile = path.join(outputDir, `${entryName}.mjs`);
    const source = fs.readFileSync(outputFile, "utf8");
    const withoutShebang = source.replace(/^#![^\n]*\n/, "");
    fs.writeFileSync(outputFile, `${generatedHeader}\n\n${withoutShebang}`);
  }
}

function compareDirs(expectedRoot, actualRoot) {
  const expectedFiles = listFilesRecursive(expectedRoot);
  const actualFiles = listFilesRecursive(actualRoot);
  if (expectedFiles.length !== actualFiles.length || expectedFiles.some((file, index) => actualFiles[index] !== file)) {
    return {
      ok: false,
      message: [
        `runtime-dist file set drifted.`,
        `expected: ${expectedFiles.join(", ") || "(empty)"}`,
        `actual: ${actualFiles.join(", ") || "(empty)"}`,
        `Run: npm run generate:runtime-dist`
      ].join("\n")
    };
  }

  for (const file of expectedFiles) {
    const expected = fs.readFileSync(path.join(expectedRoot, file), "utf8");
    const actual = fs.readFileSync(path.join(actualRoot, file), "utf8");
    if (expected !== actual) {
      return {
        ok: false,
        message: `runtime-dist content drifted for ${file}\nRun: npm run generate:runtime-dist`
      };
    }
  }

  return { ok: true, message: "runtime-dist is up to date." };
}

async function main() {
  const checkOnly = process.argv.includes("--check");
  const tempDir = fs.mkdtempSync(path.join(os.tmpdir(), "xgc-runtime-dist-"));
  const buildDir = path.join(tempDir, "runtime-dist");

  await buildRuntimeDist(checkOnly ? buildDir : runtimeDistDir);

  if (checkOnly) {
    const comparison = compareDirs(buildDir, runtimeDistDir);
    if (!comparison.ok) {
      console.error(comparison.message);
      process.exit(1);
    }
    console.log(comparison.message);
    return;
  }

  console.log(`generated runtime-dist: ${runtimeDistDir}`);
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exit(1);
});
